+      let hasSelections = false;
+      const selected: Record<string, unknown> = {};
+      const select = (key: string, selectedValue: unknown) => { hasSelections = true; selected[key] = selectedValue; };
+      const matched = patterns.some((pattern) => matchPattern(pattern, input, select)) && (!predicate || Boolean(predicate(input)));
